mapper.select:
SELECT  
  FROM  TB_EVENT_MANAGE A
 WHERE  A.EVENT_ID = #{eventId}

mapper.insert:
INSERT  INTO TB_EVENT_MANAGE
      ( EVENT_ID
      , EVENT_SE
      , EVENT_NM
      , EVENT_PURPS
      , EVENT_BGNDE
      , EVENT_ENDDE
      , EVENT_AUSPC_INSTT_NM
      , EVENT_MNGT_INSTT_NM
      , EVENT_PLACE
      , EVENT_CN
      , CT_OCCRRNC_AT
      , PARTCPT_CT
      , PSNCPA
      , REFRN_URL
      , RCEPT_BGNDE
      , RCEPT_ENDDE
      , FRST_REGISTER_ID
      , FRST_REGIST_PNTTM )
VALUES  ( #{eventId}
        , #{eventSe}
        , #{eventNm}
        , #{eventPurps}
        , #{eventBeginDe}
        , #{eventEndDe}
        , #{eventAuspcInsttNm}
        , #{eventMngtInsttNm}
        , #{eventPlace}
        , #{eventCn}
        , #{ctOccrrncAt}
        , #{partcptCt}
        , #{psncpa}
        , #{refrnUrl}
        , #{rceptBeginDe}
        , #{rceptEndDe}
        , #{frstRegisterId}
        , CURRENT_TIMESTAMP )

mapper.update:
UPDATE  TB_EVENT_MANAGE
   SET  EVENT_SE        = #{eventSe}
      , EVENT_NM        = #{eventNm}
      , EVENT_PURPS     = #{eventPurps}
      , EVENT_BGNDE     = #{eventBeginDe}
      , EVENT_ENDDE     = #{eventEndDe}
      , EVENT_PLACE     = #{eventPlace}
      , EVENT_CN        = #{eventCn}
      , LAST_UPDUSR_ID  = #{lastUpdusrId}
      , LAST_UPDT_PNTTM = CURRENT_TIMESTAMP
 WHERE  EVENT_ID = #{eventId}
